// JOYclub Stats direkt vom Profil holen (gleiche Logik wie Workflow 3a)
let fans = null, besucher = null, bewertungen = null, rating = null;
try {
  const html = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.joyclub.de/party/13140845.f3.html',
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      'Accept-Language': 'de-DE,de;q=0.9'
    }
  });
  const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);
  const parseDE = s => parseInt(s.replace(/\./g, ''), 10);
  const m1 = htmlStr.match(/(\d[\d.]*?)\s*Fans/);       if (m1) fans       = parseDE(m1[1]);
  const m2 = htmlStr.match(/(\d[\d.]*?)\s*Besucher/);   if (m2) besucher   = parseDE(m2[1]);
  const m3 = htmlStr.match(/(\d+)\s*Bewertungen/);      if (m3) bewertungen = parseInt(m3[1], 10);
  const m4 = htmlStr.match(/(\d+[.,]\d+)\s*von\s*5/);  if (m4) rating     = parseFloat(m4[1].replace(',', '.'));
} catch(e) { console.log('[Stats] Fehler:', e.message); }

// Aktive Events aus der eigenen DB holen
let events = [];
try {
  const evResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://f3-cookie-crawler:3000/api/events'
  });
  events = (evResp.list || evResp || []).slice(0, 5).map(e => ({
    name: e.EventName || '',
    datum: e.EventDatum || '',
    anmeldestand: e.Anmeldestand || ''
  })).filter(e => e.name);
} catch(e) { console.log('[Events] Fehler:', e.message); }

// Screenshot-Binary aus dem vorherigen Node durchreichen
const binary = $input.first().binary || {};

return [{
  json: {
    fans, besucher, bewertungen, rating, events,
    datum: new Date().toLocaleDateString('de-DE', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  },
  binary
}];

